private void printEntrytoCSV(APIEntry e, LinkedList<String> outputContent){
    StringBuilder sb = new StringBuilder();
    sb.append("02,");
    sb.append(cutString(e.getFieldValue(DEALER_ID), 9)+",");
    sb.append(cutString(e.getFieldValue(DEALER_NAME), 10)+",");
    sb.append(cutString(e.getFieldValue(PAYEE_ACCOUNT_NAME), 50)+",");
    sb.append(cutString(e.getFieldValue(BANK_CODE), 3)+",");
    sb.append(cutString(e.getFieldValue(BRANCH_CODE), 6)+",");
    sb.append(cutString(e.getFieldValue(ACCOUNT), 30)+",");
    sb.append(cutString(e.getFieldValue(COMPANY_REG_POST_CODE), 3)+",");
    sb.append(cutString(e.getFieldValue(COMPANY_REG_COUNTY), 10)+",");
    sb.append(cutString(e.getFieldValue(COMPANY_REG_ADDRESS), 100)+",");
    sb.append(cutString(e.getFieldValue(COMPANY_CONTACT_POST_CODE), 3)+",");
    sb.append(cutString(e.getFieldValue(COMPANY_CONTACT_COUNTY), 10)+",");
    sb.append(cutString(e.getFieldValue(COMPANY_CONTACT_ADDRESS), 100)+",");
    sb.append(cutString(e.getFieldValue(COMPANY_UNIFIED_CODE), 10)+",");
    sb.append(cutString(e.getFieldValue(INVOICE_TITLE), 80)+",");
    sb.append(cutString(e.getFieldValue(ESTABLISHMENT_DATE).replaceAll("/", ""), 8)+",");
    sb.append(cutString(e.getFieldValue(PERSON_IN_CHARGE), 18)+",");
    sb.append(cutString(e.getFieldValue(PERSON_IN_CHARGE_ID), 10)+",");
    sb.append(cutString(e.getFieldValue(PERSON_IN_CHARGE_AREA_CODE), 4)+",");
    sb.append(cutString(e.getFieldValue(PERSON_IN_CHARGE_PHONE), 10)+",");
    sb.append(e.getFieldValue(ACCORDING_POINTS)+",");
    sb.append(e.getFieldValue(ACCORDING_POINTS＿COOPERATED)+",");
    sb.append(cutString(e.getFieldValue(MAIN_PRODUCT), 50)+",");
    sb.append(cutString(e.getFieldValue(PRICE_SECTION), 50)+",");
    sb.append(cutString(e.getFieldValue(DEFERED_COMMODITY), 1)+",");
    sb.append(cutString(e.getFieldValue(PERIOD_SECTION), 50)+",");
    sb.append(cutString(e.getFieldValue(OTHERS), 100));
    
    outputContent.add(sb.toString());
}
private String cutString(String originalStr, int limit){
    if(originalStr.length() > limit){
        return originalStr.substring(0, limit);
    } else {
        return originalStr;
    }
}

