            printEntrytoCSV(e, outputContent);
            
            e.setIfQueue(false);
            e.setCreateHistory(true);
            e.setSendNotification(false);
            e.setRecalParentEntryFormula(false);
            e.setFieldValue(FILTER_STATUS, "Y");
